const response = $input.first();
const isError = response.json.error !== undefined;

const log = {
  timestamp: new Date().toISOString(),
  url: 'https://dummyjson.com/recipes/1',
  status: isError ? 'ERROR' : 'SUCCESS',
  statusCode: response.json.statusCode || 200,
  message: isError
    ? `Error: ${response.json.message || 'Error desconocido'}`
    : `Receta obtenida: ${response.json.name || 'sin nombre'} | Rating: ${response.json.rating}`,
  rating: response.json.rating || null,
  recipeId: response.json.id || null
};

console.log(JSON.stringify(log));

return [{ json: { ...response.json, _log: log } }];

